import{_ as e,o as t,c as r,a2 as o}from"./chunks/framework.DIMps2S2.js";const u=JSON.parse('{"title":"恒生银行可疑账号澄清","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"troubleshooting/hang-seng-clarification.md","filePath":"zh-CN/troubleshooting/hang-seng-clarification.md"}'),i={name:"troubleshooting/hang-seng-clarification.md"};function n(l,a,h,s,c,p){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="恒生银行可疑账号澄清" tabindex="-1">恒生银行可疑账号澄清 <a class="header-anchor" href="#恒生银行可疑账号澄清" aria-label="Permalink to &quot;恒生银行可疑账号澄清&quot;">​</a></h1><p>长桥恒生银行收款账户被标示可疑的官方声明及替代方案。</p><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h2><p>长桥证券（香港）App 内展示的恒生银行收款账户（账户号码：752027854001），被香港警务处「防骗视伏 App」标示为可疑，触发了防诈骗提示。</p><h2 id="官方声明" tabindex="-1">官方声明 <a class="header-anchor" href="#官方声明" aria-label="Permalink to &quot;官方声明&quot;">​</a></h2><p>该恒生银行账号属于长桥证券（香港）正式持有，用于为客户提供入金服务。账号本身没有任何安全问题，亦非诈骗相关账户。</p><p>长桥已就事件向相关部门申请覆核与澄清。</p><h2 id="替代方案" tabindex="-1">替代方案 <a class="header-anchor" href="#替代方案" aria-label="Permalink to &quot;替代方案&quot;">​</a></h2><p>如对该账户安全有所疑虑，可选择使用长桥提供的其他银行账号进行入金操作。所有收款账号信息请以长桥 App 内入金页面显示为准。</p><h2 id="联系方式" tabindex="-1">联系方式 <a class="header-anchor" href="#联系方式" aria-label="Permalink to &quot;联系方式&quot;">​</a></h2><p>如有进一步疑问，请联系客服：</p><p>客服热线：+852 3851 1777<br> WhatsApp：+852 5223 6373<br> 客服邮箱：service@longbridge.hk</p><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/troubleshooting">故障排查</a></li></ul>',14)])])}const _=e(i,[["render",n]]);export{u as __pageData,_ as default};
